    position: fixed;
    top: -50%; left: -50%; width: 200%; height: 200%;
    background: radial-gradient(circle at 50% 50%, rgba(99, 102, 241, 0.08), transparent 40%),
                radial-gradient(circle at 80% 20%, rgba(16, 185, 129, 0.05), transparent 30%);
    z-index: -1;
    pointer-events: none;
}

/* Glassmorphism utilities */
.glass-panel {
    background: var(--surface-light);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid var(--glass-border-light);
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.05);
}

.glass-nav {
    background: rgba(255, 255, 255, 0.75) !important;
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border-bottom: 1px solid var(--glass-border-light);
}

/* Cards */
.card {
    background: var(--surface-light);
    border: 1px solid rgba(0,0,0,0.05);
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
    border-radius: 1rem;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.card-hover:hover {
    box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
    border-color: var(--primary-color);
}

/* Buttons */
.btn {
    border-radius: 0.5rem;
    font-weight: 500;
    transition: all 0.2s ease;
}
.btn-primary { background-color: var(--primary-color); border-color: var(--primary-color); }
.btn-primary:hover { background-color: var(--primary-hover); border-color: var(--primary-hover); transform: translateY(-1px); box-shadow: 0 4px 12px rgba(99, 102, 241, 0.3); }
.btn-success { background-color: var(--success-color); border-color: var(--success-color); }
.btn-success:hover { transform: translateY(-1px); box-shadow: 0 4px 12px rgba(16, 185, 129, 0.3); }

/* Chat specific */
.chat-card { border-radius: 1rem; }
.chat-card.border-success { border-color: var(--success-color) !important; background-color: rgba(16, 185, 129, 0.03); }
.suggest-btn { border-radius: 2rem; padding: 0.5rem 1rem; font-size: 0.85rem; border: 1px solid var(--primary-color); color: var(--primary-color); background: transparent; transition: all 0.2s ease; margin-bottom: 0.5rem; }
.suggest-btn:hover { background-color: var(--primary-color); color: white; box-shadow: 0 4px 10px rgba(99, 102, 241, 0.2); }

/* Inputs */
.form-control, .form-select { border-radius: 0.75rem; border: 1px solid #e2e8f0; padding: 0.75rem 1rem; transition: all 0.2s; background: rgba(255,255,255,0.9); }
.form-control:focus, .form-select:focus { border-color: var(--primary-color); box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.15); background: #fff; }
.input-group-text { border-radius: 0.75rem; background: rgba(248,250,252,0.8); border: 1px solid #e2e8f0; }

/* Text Gradient */
.text-gradient { background: linear-gradient(135deg, var(--primary-color), var(--success-color)); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }

/* Modal enhancements */
.modal-content { border-radius: 1.25rem; border: none; box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25); overflow: hidden; }
.modal-header { border-bottom: 1px solid rgba(0,0,0,0.05); }
.modal-footer { border-top: 1px solid rgba(0,0,0,0.05); }

/* Scrollbar */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.15); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: rgba(0,0,0,0.3); }

/* Answer content — transparent background to match app */
.answer-content { font-size: 1rem; line-height: 1.6; word-wrap: break-word; background: transparent; }
.answer-content p { margin-top: 0; margin-bottom: 1rem; }
.answer-content p:last-child { margin-bottom: 0; }
.answer-content h1, .answer-content h2, .answer-content h3, .answer-content h4, .answer-content h5, .answer-content h6 { margin-top: 1.5rem; margin-bottom: 0.5rem; font-weight: 600; line-height: 1.25; }
.answer-content h1 { font-size: 1.5em; border-bottom: 1px solid var(--glass-border-light); padding-bottom: .3em; }
.answer-content h2 { font-size: 1.25em; border-bottom: 1px solid var(--glass-border-light); padding-bottom: .3em; }
.answer-content h3 { font-size: 1.1em; }
.answer-content ul, .answer-content ol { margin-top: 0; margin-bottom: 1rem; padding-left: 1.5em; }
.answer-content li { margin-bottom: 0.25em; }
.answer-content blockquote { margin: 0 0 1rem; padding: 0 1em; color: var(--text-muted-light); border-left: 0.25em solid #dfe2e5; }
.answer-content pre { background: transparent; padding: 0; overflow-x: auto; font-family: ui-monospace, SFMono-Regular, Consolas, 'Liberation Mono', Menlo, monospace; font-size: 0.9em; margin-bottom: 1rem; }
.answer-content code { font-family: ui-monospace, SFMono-Regular, Consolas, 'Liberation Mono', Menlo, monospace; background: transparent; padding: 0; border-radius: 6px; font-size: 0.9em; }
.answer-content table { width: 100%; margin-bottom: 1rem; color: inherit; border-collapse: collapse; }
.answer-content table th, .answer-content table td { padding: 0.5rem; border: 1px solid var(--glass-border-light); }

const api = {
    getToken: () => localStorage.getItem('access_token'),
    setToken: (access, refresh) => {
        localStorage.setItem('access_token', access);
        if (refresh) localStorage.setItem('refresh_token', refresh);
    },
    clearToken: () => {
        localStorage.removeItem('access_token');
        localStorage.removeItem('refresh_token');
    },
    isAuthenticated: () => !!localStorage.getItem('access_token'),

    request: async (url, method = 'GET', body = null) => {
        const attempt = async (retryCount = 0) => {
            const headers = { 'Content-Type': 'application/json' };
            const token = api.getToken();
            if (token) headers['Authorization'] = `Bearer ${token}`;

            const opts = { method, headers };
            if (body) opts.body = JSON.stringify(body);

            const resp = await fetch(url, opts);
            if (resp.status === 401 && retryCount < 1) {
                const refreshed = await api.refreshToken();
                if (refreshed) return attempt(1);
                api.clearToken();
                window.location.href = '/login/';
                return null;
            }
            if (!resp.ok) {
                const err = await resp.json().catch(() => ({}));
                showAlert(err.detail || Object.values(err).flat().join(', ') || 'Request failed', 'danger');
                return null;
            }
            const text = await resp.text();
            return text ? JSON.parse(text) : null;
        };

        try {
            return await attempt(0);
        } catch (e) {
            showAlert('Network error. Is the server running?', 'danger');
            return null;
        }
    },

    upload: async (url, formData) => {
        const token = api.getToken();
        const headers = {};
        if (token) headers['Authorization'] = `Bearer ${token}`;

        try {
            const resp = await fetch(url, { method: 'POST', headers, body: formData });
            if (resp.status === 401) {
                const refreshed = await api.refreshToken();
                if (refreshed) {
                    headers['Authorization'] = `Bearer ${api.getToken()}`;
                    const retry = await fetch(url, { method: 'POST', headers, body: formData });
                    return retry.ok ? retry.json() : null;
                }
                api.clearToken();
                window.location.href = '/login/';
                return null;
            }
            if (!resp.ok) {
                const err = await resp.json().catch(() => ({}));
                showAlert(Object.values(err).flat().join(', '), 'danger');
                return null;
            }
            showAlert('Upload successful!', 'success');
            return resp.json();
        } catch (e) {
            showAlert('Upload failed. Is the server running?', 'danger');
            return null;
        }
    },

    login: async (email, password) => {
        const data = await api.request('/auth/login/', 'POST', { email, password });
        if (data) {
            api.setToken(data.access, data.refresh);
            return data;
        }
        return null;
    },

    register: async (firstName, lastName, email, password) => {
        const data = await api.request('/auth/register/', 'POST', {
            first_name: firstName, last_name: lastName, email, password
        });
        if (data) {
            api.setToken(data.access, data.refresh);
            return data;
        }
        return null;
    },

    logout: () => { api.clearToken(); window.location.href = '/'; },

    refreshToken: async () => {
        const refresh = localStorage.getItem('refresh_token');
        if (!refresh) return false;
        try {
            const resp = await fetch('/auth/token/refresh/', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ refresh })
            });
            if (resp.ok) {
                const data = await resp.json();
                api.setToken(data.access);
                return true;
            }
            return false;
        } catch { return false; }
    }
};

function showAlert(msg, type = 'info') {
    const container = document.getElementById('alerts');
    const alert = document.createElement('div');
    alert.className = `alert alert-${type} alert-dismissible fade show`;
    alert.innerHTML = `${msg}<button type="button" class="btn-close" data-bs-dismiss="alert"></button>`;
    container.appendChild(alert);
    setTimeout(() => alert.remove(), 5000);
}

// Dark mode removed per user request

document.addEventListener('DOMContentLoaded', () => {
    const authNav = document.getElementById('authNav');
    const indexAuth = document.getElementById('indexAuth');
    const indexApp = document.getElementById('indexApp');

    // Theme logic removed
    if (api.isAuthenticated()) {
        if (authNav) {
            authNav.innerHTML = `
                <li class="nav-item"><a class="nav-link" href="#" onclick="api.logout()"><i class="bi bi-box-arrow-right me-1"></i>Logout</a></li>
            `;
        }
        if (indexAuth && indexApp) {
            indexAuth.classList.add('d-none');
            indexApp.classList.remove('d-none');
        }
    } else {
        if (authNav) {
            authNav.innerHTML = `
                <li class="nav-item"><a class="nav-link" href="/login/"><i class="bi bi-box-arrow-in-right me-1"></i>Login</a></li>
                <li class="nav-item"><a class="nav-link" href="/register/"><i class="bi bi-person-plus me-1"></i>Register</a></li>
            `;
        }
        const protectedLinks = document.querySelectorAll('#navLinks .nav-link');
        protectedLinks.forEach(l => l.addEventListener('click', (e) => {
            if (!api.isAuthenticated()) {
                e.preventDefault();
                window.location.href = '/login/';
            }
        }));
    }
});

{% extends "base.html" %}
{% block title %}Ask Questions{% endblock %}
{% block content %}
<div class="row justify-content-center">
    <div class="col-lg-8">
        <div class="text-center mb-5 mt-3">
            <h2 class="fw-bold text-gradient"><i class="bi bi-magic me-2"></i>Global Knowledge Search</h2>
            <p class="text-muted">Ask a question and we'll search across all your indexed documents to find the answer.</p>
        </div>

        <div class="mb-5">
            <form id="askForm">
                <div class="glass-panel p-2 rounded-4 shadow-sm">
                    <textarea class="form-control border-0 bg-transparent" id="question" rows="3" placeholder="What would you like to know?" required style="box-shadow: none; resize: none; font-size: 1.1rem;"></textarea>
                    <div class="d-flex justify-content-end mt-2">
                        <button type="submit" class="btn btn-primary rounded-pill px-4 shadow-sm">
                            <i class="bi bi-stars me-2"></i>Generate Answer
                        </button>
                    </div>
                </div>
            </form>
        </div>

        <div id="answerSection" class="d-none chat-card">
            <div class="d-flex align-items-start mb-5">
                <div class="flex-shrink-0 me-3 border rounded-circle bg-white shadow-sm d-flex align-items-center justify-content-center" style="width: 40px; height: 40px;">
                    <i class="bi bi-stars text-primary fs-5"></i>
                </div>
                <div class="flex-grow-1">
                    <div id="answerText" class="answer-content" style="font-size: 1.1rem; line-height: 1.7;"></div>
                </div>
            </div>

            <h6 class="text-muted fw-bold mb-3 ms-2"><i class="bi bi-journal-text me-2"></i>Sources Used</h6>
            <div class="row g-3" id="sourcesList"></div>
        </div>

        <div id="loadingAnswer" class="text-center d-none py-5">
            <div class="spinner-grow text-primary mb-3" style="width: 3rem; height: 3rem;" role="status"></div>
            <h5 class="text-muted fw-bold">Wait for a minute...</h5>
            <p class="text-muted small">Scanning your secure vector database</p>
        </div>
    </div>
</div>
{% endblock %}
{% block scripts %}
<script>
if (!api.isAuthenticated()) { window.location.href = '/login/'; }

document.getElementById('askForm').addEventListener('submit', async (e) => {
    e.preventDefault();
    const question = document.getElementById('question').value;
    document.getElementById('answerSection').classList.add('d-none');
    document.getElementById('loadingAnswer').classList.remove('d-none');

    // Disable inputs
    const askInput = document.getElementById('question');
    const submitBtn = e.target.querySelector('button[type="submit"]');
    askInput.disabled = true;
    submitBtn.disabled = true;

    const data = await api.request('/api/documents/ask/', 'POST', {
        question: question,
        n_results: 5
    });

    document.getElementById('loadingAnswer').classList.add('d-none');

    // Re-enable inputs
    askInput.disabled = false;
    submitBtn.disabled = false;
    askInput.focus();

    if (!data) { showAlert('Failed to get answer. Try logging in again.', 'warning'); return; }

    let formatted = data.answer;
    if (typeof marked !== 'undefined' && marked.parse) {
        try { formatted = marked.parse(data.answer); } catch(e) {
            formatted = data.answer.replace(/[#*_\[\]`>|]/g, '').trim();
        }
    }
    document.getElementById('answerText').innerHTML = formatted;
    document.getElementById('sourcesList').innerHTML = data.sources.map(s => `
        <div class="col-md-6">
            <div class="glass-panel p-3 rounded-4 h-100 card-hover">
                <div class="d-flex justify-content-between mb-2">
                        <small class="fw-bold text-primary text-truncate"><i class="bi bi-file-earmark-text me-1"></i>${s.title}</small>
                    </div>
                <p class="mb-0 small text-muted" style="display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden;">"${s.text}"</p>
            </div>
        </div>
    `).join('');
    document.getElementById('answerSection').classList.remove('d-none');
});
</script>
{% endblock %}

