</div>

<div class="modal fade" id="previewModal" tabindex="-1">
    <div class="modal-dialog modal-lg modal-dialog-scrollable">
        <div class="modal-content">
            <div class="modal-header">
                <h5 class="modal-title" id="previewTitle"></h5>
                <button type="button" class="btn-close" data-bs-dismiss="modal"></button>
            </div>
            <div class="modal-body">
                <div id="previewMeta" class="mb-3"></div>
                <div id="previewSummary" class="d-none mb-3 p-3 rounded border border-success">
                    <strong><i class="bi bi-file-text me-1"></i>Summary</strong>
                    <p class="mb-0 mt-1 small" id="previewSummaryText"></p>
                </div>
                <div class="d-flex gap-2 mb-2">
                    <button class="btn btn-sm btn-outline-success" id="summarizeBtn" onclick="summarizeDoc()">
                        <i class="bi bi-file-text me-1"></i>Summarize
                    </button>
                </div>
                <pre id="previewContent" class="bg-light p-3 rounded" style="white-space:pre-wrap;max-height:50vh;overflow-y:auto;"></pre>
            </div>
        </div>
    </div>
</div>

<div class="modal fade" id="deleteModal" tabindex="-1">
    <div class="modal-dialog modal-sm">
        <div class="modal-content">
            <div class="modal-header">
                <h5 class="modal-title">Delete Document</h5>
                <button type="button" class="btn-close" data-bs-dismiss="modal"></button>
            </div>
            <div class="modal-body">
                <p>Delete <strong id="deleteDocName"></strong>? This will also remove all vector embeddings and chat history.</p>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" data-bs-dismiss="modal">Cancel</button>
                <button class="btn btn-danger" id="confirmDeleteBtn">Delete</button>
            </div>
        </div>
    </div>
</div>
{% endblock %}
{% block scripts %}
<script>
let deleteTargetId = null;
let currentPreviewId = null;

async function loadDocuments() {
    const docs = await api.request('/api/documents/');
    const container = document.getElementById('documentsList');
    if (!docs || docs.length === 0) {
        container.innerHTML = '<div class="col-12 text-center py-5"><p class="text-muted"><i class="bi bi-inbox me-2"></i>No documents yet. Upload your first document!</p></div>';
        return;
    }
    container.innerHTML = docs.map((d, i) => {
        const indexed = d.chunk_count > 0;
        return `
        <div class="col-md-4 mb-4">
            <div class="card glass-panel h-100 card-hover border-0">
                <div class="card-body d-flex flex-column p-4">
                    <div class="d-flex justify-content-between align-items-start mb-3">
                        <div class="p-2 bg-primary bg-opacity-10 rounded text-primary">
                            <i class="bi bi-file-earmark-text fs-4"></i>
                        </div>
                        ${indexed ? '<span class="badge bg-success bg-opacity-10 text-success border border-success rounded-pill px-2 py-1" title="Indexed"><i class="bi bi-check-circle-fill me-1"></i>Ready</span>' : '<span class="badge bg-warning bg-opacity-10 text-warning border border-warning rounded-pill px-2 py-1" title="Processing"><i class="bi bi-hourglass-split me-1"></i>Indexing</span>'}
                    </div>
                    <h5 class="card-title fw-bold mb-1 text-truncate" title="${d.title}">${d.title}</h5>
                    <p class="small text-muted mb-4">${d.file_type.toUpperCase()} &middot; ${new Date(d.created_at).toLocaleDateString()}</p>
                    <div class="mt-auto">
                        <div class="d-flex gap-2">
                            <button class="btn btn-light rounded-circle p-2 flex-shrink-0 shadow-sm" onclick="previewDoc(${d.id})" title="Preview"><i class="bi bi-eye text-primary"></i></button>
                            <a href="/documents/${d.id}/ask/" class="btn btn-success flex-grow-1 rounded-pill shadow-sm" title="Ask Questions"><i class="bi bi-chat-right-text me-2"></i>Ask</a>
                            <button class="btn btn-light rounded-circle p-2 flex-shrink-0 shadow-sm" onclick="confirmDelete(${d.id}, '${d.title.replace(/'/g, "\\'")}')" title="Delete"><i class="bi bi-trash text-danger"></i></button>
                        </div>
                    </div>
                </div>
            </div>
        </div>`}).join('');
}

async function loadSuggestedQuestions() {
    const data = await api.request('/api/documents/suggest-global/');
    const container = document.getElementById('suggestedQuestions');
    if (!data || !data.questions || data.questions.length === 0) {
        container.innerHTML = '<p class="text-muted small mb-0">Upload documents to get AI-suggested questions.</p>';
        return;
    }
    container.innerHTML = data.questions.map(q =>
        `<button class="btn btn-outline-secondary btn-sm rounded-pill suggest-btn shadow-sm" onclick="askGlobal('${q.replace(/'/g, "\\'")}')">${q}</button>`
    ).join('');
}

async function showAnswer(data) {
    const container = document.getElementById('answerResult');
    const content = document.getElementById('answerContent');
    const sourcesDiv = document.getElementById('answerSources');

    let formatted = data.answer;
    if (typeof marked !== 'undefined' && marked.parse) {
        try { formatted = marked.parse(data.answer); } catch(e) {
            formatted = data.answer.replace(/[#*_\[\]`>|]/g, '').trim();
        }
    }
    content.innerHTML = formatted;

    if (data.sources && data.sources.length) {
        document.getElementById('sourceCount').textContent = data.sources.length;
        document.getElementById('sourceList').innerHTML = [...new Set(data.sources.map(s => s.title))].map(t =>
            `<span class="badge bg-light text-dark border">${t}</span>`
        ).join('');
        sourcesDiv.classList.remove('d-none');
    } else {
        sourcesDiv.classList.add('d-none');
    }

    container.classList.remove('d-none');
    container.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

let isLoading = false;

function setLoading(loading) {
    isLoading = loading;
    const input = document.getElementById('askInput');
    const btn = document.querySelector('#askInput + .btn');
    const suggestBtns = document.querySelectorAll('#suggestedQuestions .suggest-btn');
    input.disabled = loading;
    if (btn) btn.disabled = loading;
    suggestBtns.forEach(b => b.disabled = loading);
    if (loading) {
        input.placeholder = 'Wait for a minute...';
    } else {
        input.placeholder = 'Or type your own question...';
        input.focus();
    }
}

async function askGlobal(question) {
    if (isLoading) return;
    setLoading(true);
    const container = document.getElementById('answerResult');
    container.classList.add('d-none');

    const data = await api.request('/api/documents/ask/', 'POST', {
        question: question,
        n_results: 10
    });

    setLoading(false);

    if (!data || data.error) {
        showAlert('Could not generate answer.', 'warning');
        return;
    }
    showAnswer(data);
}

async function askGlobalQuestion() {
    const input = document.getElementById('askInput');
    const question = input.value.trim();
    if (!question || isLoading) return;
    input.value = '';
    await askGlobal(question);
}

let summaryCache = {};

async function previewDoc(docId) {
    currentPreviewId = docId;
    const data = await api.request(`/api/documents/${docId}/preview/`);
    if (!data) return;
    document.getElementById('previewTitle').textContent = data.title;
    document.getElementById('previewMeta').innerHTML = `
        <span class="badge bg-secondary me-1">${data.file_type.toUpperCase()}</span>
        <span class="badge bg-info me-1">${data.word_count} words</span>
        <span class="badge bg-${data.indexed ? 'success' : 'warning'}">${data.indexed ? `${data.chunk_count} chunks indexed` : 'Not indexed yet'}</span>
    `;
    document.getElementById('previewContent').textContent = data.content;
    document.getElementById('previewSummary').classList.add('d-none');
    if (summaryCache[docId]) {
        document.getElementById('previewSummaryText').textContent = summaryCache[docId];
        document.getElementById('previewSummary').classList.remove('d-none');
    }
    document.getElementById('summarizeBtn').disabled = false;
    document.getElementById('summarizeBtn').innerHTML = '<i class="bi bi-file-text me-1"></i>Summarize';
    new bootstrap.Modal(document.getElementById('previewModal')).show();
}

async function summarizeDoc() {
    if (!currentPreviewId) return;
    const btn = document.getElementById('summarizeBtn');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm me-1"></span>Summarizing...';
    const data = await api.request(`/api/documents/${currentPreviewId}/summarize/`);
    if (data && data.summary) {
        summaryCache[currentPreviewId] = data.summary;
        document.getElementById('previewSummaryText').textContent = data.summary;
        document.getElementById('previewSummary').classList.remove('d-none');
    }
    btn.disabled = false;
    btn.innerHTML = '<i class="bi bi-file-text me-1"></i>Summarize';
}

function confirmDelete(docId, title) {
    deleteTargetId = docId;
    document.getElementById('deleteDocName').textContent = title;
    new bootstrap.Modal(document.getElementById('deleteModal')).show();
}

document.getElementById('confirmDeleteBtn').addEventListener('click', async () => {
    if (!deleteTargetId) return;
    const result = await api.request(`/api/documents/${deleteTargetId}/`, 'DELETE');
    if (result !== false) {
        bootstrap.Modal.getInstance(document.getElementById('deleteModal')).hide();
        loadDocuments();
    }
});

function validateFileType() {
    const fileInput = document.getElementById('docFile');
    const typeSelect = document.getElementById('docType');
    const errorDiv = document.getElementById('fileTypeError');
    const errorMsg = document.getElementById('fileTypeErrorMsg');
    const submitBtn = document.getElementById('uploadSubmitBtn');

    errorDiv.classList.add('d-none');
    submitBtn.disabled = true;

    const file = fileInput.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = function(e) {
        const bytes = new Uint8Array(e.target.result);
        const expected = typeSelect.value;
        let valid = true;
        let msg = '';

        // Reject image files regardless of selected type
        if (bytes[0] === 0x89 && bytes[1] === 0x50 && bytes[2] === 0x4E && bytes[3] === 0x47) {
            valid = false; msg = 'PNG images are not supported — upload a PDF, DOCX, or TXT document.';
        } else if (bytes[0] === 0xFF && bytes[1] === 0xD8 && bytes[2] === 0xFF) {
            valid = false; msg = 'JPEG images are not supported — upload a PDF, DOCX, or TXT document.';
        } else if (bytes[0] === 0x47 && bytes[1] === 0x49 && bytes[2] === 0x46) {
            valid = false; msg = 'GIF images are not supported — upload a PDF, DOCX, or TXT document.';
        } else if (bytes[0] === 0x42 && bytes[1] === 0x4D) {
            valid = false; msg = 'BMP images are not supported — upload a PDF, DOCX, or TXT document.';
        } else if (expected === 'pdf') {
            valid = bytes[0] === 0x25 && bytes[1] === 0x50 && bytes[2] === 0x44 && bytes[3] === 0x46 && bytes[4] === 0x2D;
            msg = 'File does not start with %PDF- — select PDF as file type only for PDF documents.';
        } else if (expected === 'docx') {
            valid = bytes[0] === 0x50 && bytes[1] === 0x4B;
            msg = 'File does not start with PK (ZIP header) — select DOCX only for Word documents.';
        } else if (expected === 'txt') {
            valid = !bytes.includes(0x00);
            msg = 'File contains null bytes or binary data — select TXT only for plain text files.';
        }

        if (!valid) {
            errorMsg.textContent = msg;
            errorDiv.classList.remove('d-none');
            submitBtn.disabled = true;
        } else {
            submitBtn.disabled = false;
        }
    };
    reader.readAsArrayBuffer(file.slice(0, 8));
}

document.getElementById('docType').addEventListener('change', validateFileType);

document.getElementById('uploadForm').addEventListener('submit', async (e) => {
    e.preventDefault();
    const submitBtn = document.getElementById('uploadSubmitBtn');
    submitBtn.disabled = true;
    submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-1"></span>Wait for a minute...';

    const formData = new FormData();
    formData.append('title', document.getElementById('docTitle').value);
    formData.append('file_type', document.getElementById('docType').value);
    formData.append('file', document.getElementById('docFile').files[0]);
    const result = await api.upload('/api/documents/', formData);

    submitBtn.disabled = false;
    submitBtn.innerHTML = 'Upload';

    if (result) {
        bootstrap.Modal.getInstance(document.getElementById('uploadModal')).hide();
        document.getElementById('uploadForm').reset();
        loadDocuments();
    }
});

loadDocuments();
loadSuggestedQuestions();
</script>
