<script>
if (!api.isAuthenticated()) { window.location.href = '/login/'; }

const DOC_ID = {{ doc_id }};
let chatHistory = [];

async function loadDocInfo() {
    const docs = await api.request('/api/documents/');
    if (!docs) { window.location.href = '/documents/'; return; }
    const doc = docs.find(d => d.id === DOC_ID);
    if (!doc) { window.location.href = '/documents/'; return; }
    document.getElementById('docTitle').innerHTML = `<i class="bi bi-file-earmark-text me-2"></i>${doc.title}`;
    document.getElementById('docMeta').textContent = `${doc.file_type.toUpperCase()} · ${new Date(doc.created_at).toLocaleDateString()}`;
}

async function loadSuggestedQuestions() {
    const data = await api.request(`/api/documents/${DOC_ID}/suggest/`);
    if (!data || !data.questions) return;
    const container = document.getElementById('suggestionsList');
    container.innerHTML = data.questions.map(q =>
        `<button class="btn btn-outline-success btn-sm suggest-btn" onclick="askSuggested('${q.replace(/'/g, "\\'")}')">${q}</button>`
    ).join('');
    document.getElementById('suggestedQuestions').classList.remove('d-none');
}

function askSuggested(question) {
    document.getElementById('question').value = question;
    document.getElementById('askForm').dispatchEvent(new Event('submit'));
}

async function loadHistory() {
    const history = await api.request(`/api/history/chat/?document_id=${DOC_ID}`);
    const container = document.getElementById('chatHistory');
    if (!history || history.length === 0) {
        document.getElementById('emptyState').classList.remove('d-none');
        document.getElementById('suggestedQuestions').classList.remove('d-none');
        container.innerHTML = '';
        return;
    }
    document.getElementById('emptyState').classList.add('d-none');
    chatHistory = history;
    container.innerHTML = history.map((h, i) => `
        <div class="mb-5 chat-card" style="animation-delay:${i*0.03}s">
            <div class="d-flex justify-content-end mb-4">
                <div class="bg-secondary bg-opacity-10 px-4 py-3 rounded-4 text-dark" style="max-width: 75%;">
                    <p class="mb-0 fs-6">${h.question}</p>
                </div>
            </div>
            <div class="d-flex align-items-start">
                <div class="flex-shrink-0 me-3 mt-1 border rounded-circle bg-white shadow-sm d-flex align-items-center justify-content-center" style="width: 36px; height: 36px;">
                    <i class="bi bi-stars text-success"></i>
                </div>
                <div class="flex-grow-1" style="max-width: 90%;">
                    <div class="answer-content">${marked.parse(h.answer)}</div>
                    <div class="d-flex justify-content-between align-items-center mt-2 pt-2">
                        ${h.sources && h.sources.length ? `<small class="badge bg-secondary bg-opacity-10 text-secondary border rounded-pill fw-normal"><i class="bi bi-link-45deg me-1"></i>${h.sources.length} sources</small>` : '<span></span>'}
                        <small class="text-muted" style="font-size: 0.75rem;">${new Date(h.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</small>
                    </div>
                </div>
            </div>
        </div>
    `).join('');
}

async function exportChat() {
    if (chatHistory.length === 0) {
        showAlert('No chat history to export.', 'warning');
        return;
    }
    const docTitle = document.getElementById('docTitle').textContent.trim();
    let md = `# Q&A: ${docTitle}\n\n`;
    chatHistory.forEach(h => {
        md += `## Q: ${h.question}\n\n${h.answer}\n\n`;
        if (h.sources && h.sources.length) {
            md += `*Sources: ${h.sources.length}*\n\n`;
        }
        md += `---\n\n`;
    });
    const blob = new Blob([md], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${docTitle.replace(/[^a-zA-Z0-9]/g, '_')}_qa.md`;
    a.click();
    URL.revokeObjectURL(url);
    showAlert('Chat exported!', 'success');
}

document.getElementById('askForm').addEventListener('submit', async (e) => {
    e.preventDefault();
    const question = document.getElementById('question').value.trim();
    if (!question) return;

    document.getElementById('loadingSpinner').classList.remove('d-none');
    document.getElementById('emptyState').classList.add('d-none');

    // Disable inputs
    const askInput = document.getElementById('question');
    const submitBtn = e.target.querySelector('button[type="submit"]');
    askInput.disabled = true;
    submitBtn.disabled = true;
    document.querySelectorAll('.suggest-btn').forEach(btn => btn.disabled = true);

    const historyContext = chatHistory.slice(-3).map(h => ({
        question: h.question,
        answer: h.answer
    }));

    const data = await api.request('/api/documents/ask/', 'POST', {
        question: question,
        document_id: DOC_ID,
        n_results: 5,
        history: historyContext
    });

    document.getElementById('loadingSpinner').classList.add('d-none');
    document.getElementById('question').value = '';

    // Re-enable inputs
    askInput.disabled = false;
    submitBtn.disabled = false;
    document.querySelectorAll('.suggest-btn').forEach(btn => btn.disabled = false);
    askInput.focus();

    if (data) {
        const container = document.getElementById('chatHistory');
        const entry = {
            question: question,
            answer: data.answer,
            sources: data.sources || [],
            created_at: new Date().toISOString()
        };
        chatHistory.push(entry);
        container.insertAdjacentHTML('afterbegin', `
            <div class="mb-5 chat-card">
                <div class="d-flex justify-content-end mb-4">
                    <div class="bg-secondary bg-opacity-10 px-4 py-3 rounded-4 text-dark" style="max-width: 75%;">
                        <p class="mb-0 fs-6">${question}</p>
                    </div>
                </div>
                <div class="d-flex align-items-start">
                    <div class="flex-shrink-0 me-3 mt-1 border rounded-circle bg-white shadow-sm d-flex align-items-center justify-content-center" style="width: 36px; height: 36px;">
                        <i class="bi bi-stars text-success"></i>
                    </div>
                    <div class="flex-grow-1" style="max-width: 90%;">
                        <div>${marked.parse(data.answer)}</div>
                        <div class="d-flex justify-content-between align-items-center mt-2 pt-2">
                            ${data.sources && data.sources.length ? `<small class="badge bg-secondary bg-opacity-10 text-secondary border rounded-pill fw-normal"><i class="bi bi-link-45deg me-1"></i>${data.sources.length} sources</small>` : '<span></span>'}
                            <small class="text-muted" style="font-size: 0.75rem;">Just now</small>
                        </div>
                    </div>
                </div>
            </div>
        `);
    }
});

loadDocInfo();
loadHistory();
loadSuggestedQuestions();
</script>
