        ].join("\n")
      )
    }

  }

  private getClient(): OpenAI {

    if (this.client) {
      return this.client
    }

    this.client = new OpenAI({
      apiKey: this.apiKey!
    })

    return this.client
  }

  async generate(prompt: string): Promise<string> {

    const client = this.getClient()

    try {

      const response = await client.chat.completions.create({
        model: this.model,
        messages: [
          { role: "user", content: prompt }
        ]
      })

      const text =
        response?.choices?.[0]?.message?.content ?? ""

      if (!text.trim()) {
        throw new LLMProviderError(
          "OpenAI returned no text"
        )
      }

      return text.trim()

    } catch (err: any) {

      const message =
        err?.message ? String(err.message) : String(err)

      throw new LLMProviderError(
        `OpenAI request failed: ${message}`
      )
    }
  }

  doctor(): string[] {
    return [
      `OPENAI_API_KEY set: ${Boolean(this.apiKey)}`,
      `model: ${this.model}`
    ]
  }

}

import { LLMProvider, LLMProviderError } from "./base.js";

const BASE_URL = "https://openrouter.ai/api/v1";

type OpenRouterConfig = {
  api_key?: string;
  model?: string;
};

export class OpenRouterProvider implements LLMProvider {
  name = "openrouter";

  private apiKey: string;
  private model: string;
  private client: any | null = null;

  constructor(config: OpenRouterConfig = {}) {
    this.apiKey = config.api_key ?? "";
    this.model = config.model as string;

    this.validateConfig();
  }

  validateConfig(): void {
    if (!this.apiKey || !this.apiKey.trim()) {
      throw new LLMProviderError(
        "OpenRouter provider requires an API key.\n" +
          "Run `explainthisrepo init` or set providers.openrouter.api_key.",
      );
    }

    if (!this.model || !String(this.model).trim()) {
      throw new LLMProviderError(
        "OpenRouter provider requires a model.\n" +
          "Set providers.openrouter.model (e.g. openai/gpt-4o, deepseek/deepseek-chat).",
      );
    }
  }

  private getClient() {
    if (this.client) {
      return this.client;
    }

    try {
      const { OpenAI } = require("openai");

      this.client = new OpenAI({
        apiKey: this.apiKey,
        baseURL: BASE_URL,
      });

      return this.client;
    } catch {
      throw new LLMProviderError(
        "OpenRouter support is not installed.\n" +
          "Install it with:\n" +
          "  npm install openai",
      );
    }
  }

  async generate(prompt: string): Promise<string> {
    const client = this.getClient();

    let response: any;

    try {
      response = await client.chat.completions.create({
        model: this.model,
        messages: [{ role: "user", content: prompt }],
      });
    } catch (err: any) {
      const message = err?.message ? String(err.message) : String(err);
      throw new LLMProviderError(`OpenRouter request failed: ${message}`);
    }

    let text: string | null = null;

    try {
      text = response?.choices?.[0]?.message?.content ?? null;
    } catch {
      text = null;
    }

    if (!text || !text.trim()) {
      throw new LLMProviderError("OpenRouter returned no text");
    }

    return text.trim();
  }

  async doctor(): Promise<string[]> {
    return [
      `OPENROUTER_API_KEY set: ${Boolean(this.apiKey)}`,
      `model: ${this.model}`,
    ];
  }
}

import { loadConfig } from "../config.js";
import { LLMProvider, LLMProviderError } from "./base.js";

import { GeminiProvider } from "./gemini.js";
import { OpenAIProvider } from "./openai.js";
import { OllamaProvider } from "./ollama.js";
import { AnthropicProvider } from "./anthropic.js";
import { OpenRouterProvider } from "./openrouter.js";

type ProviderConstructor = new (config?: any) => LLMProvider;

const PROVIDER_REGISTRY: Record<string, ProviderConstructor> = {
  gemini: GeminiProvider,
  openai: OpenAIProvider,
  ollama: OllamaProvider,
  anthropic: AnthropicProvider,
  openrouter: OpenRouterProvider,
};

export function listProviders(): string[] {
  return Object.keys(PROVIDER_REGISTRY);
}

export function getProvider(name: string): LLMProvider {
  const providerName = name.toLowerCase();

  const Provider = PROVIDER_REGISTRY[providerName];

  if (!Provider) {
    throw new LLMProviderError(`Unknown LLM provider '${providerName}'`);
  }

  const config = loadConfig();

  const providerConfig = config?.providers?.[providerName] ?? {};

  return new Provider(providerConfig);
}

export function getActiveProvider(override?: string): LLMProvider {
  if (override) {
    return getProvider(override);
  }

  const config = loadConfig();

  const defaultProvider = config?.llm?.provider;

  if (!defaultProvider) {
    throw new LLMProviderError(
      "No LLM provider configured. Run 'explainthisrepo init'.",
    );
  }

  return getProvider(defaultProvider);
}

