using System;
using System.Diagnostics;
using System.IO;
using System.Runtime.InteropServices;

namespace ExplainThisRepo
{
    class Program
    {
        static int Main(string[] args)
        {
            try
            {
                string binaryPath = GetBinaryPath();

                var processInfo = new ProcessStartInfo
                {
                    FileName = binaryPath,
                    UseShellExecute = false,
                    CreateNoWindow = true
                };

                foreach (var arg in args)
                {
                    processInfo.ArgumentList.Add(arg);
                }

                using var process = Process.Start(processInfo);
                if (process != null)
                {
                    process.WaitForExit();
                    return process.ExitCode;
                }

                return 1;
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine($"error: {ex.Message}");
                return 1;
            }
        }

        static string GetBinaryPath()
        {
            string targetKey = GetTargetKey();
            string binaryName = RuntimeInformation.IsOSPlatform(OSPlatform.Windows) ? "explainthisrepo.exe" : "explainthisrepo";

            string launcherDir = AppContext.BaseDirectory;
            string binaryPath = Path.Combine(launcherDir, "native", targetKey, binaryName);

            if (!File.Exists(binaryPath))
            {
                throw new FileNotFoundException($"Bundled binary not found: {binaryPath}");
            }

            return binaryPath;
        }

        static string GetTargetKey()
        {
            if (RuntimeInformation.IsOSPlatform(OSPlatform.OSX))
            {
                return RuntimeInformation.OSArchitecture == Architecture.Arm64 ? "darwin-arm64" : "darwin-x64";
            }
            if (RuntimeInformation.IsOSPlatform(OSPlatform.Linux))
            {
                return RuntimeInformation.OSArchitecture == Architecture.Arm64 ? "linux-arm64" : "linux-x64";
            }
            if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
            {
                return "win-x64";
            }

            throw new PlatformNotSupportedException($"Unsupported platform: {RuntimeInformation.OSDescription} {RuntimeInformation.OSArchitecture}");
        }
    }
}

from __future__ import annotations

import os
import platform
import tomllib
from pathlib import Path
from typing import Any, Dict, Optional

CONFIG_DIR_NAME = "ExplainThisRepo"
CONFIG_FILE_NAME = "config.toml"


def get_config_path() -> Path:
    system = platform.system().lower()

    if system == "windows":
        appdata = os.environ.get("APPDATA")
        if not appdata:
            raise RuntimeError("APPDATA environment variable is not set")
        base = Path(appdata) / CONFIG_DIR_NAME
    else:
        xdg = os.environ.get("XDG_CONFIG_HOME")
        if xdg:
            base = Path(xdg) / "explainthisrepo"
        else:
            base = Path.home() / ".config" / "explainthisrepo"

    return base / CONFIG_FILE_NAME


def ensure_config_dir() -> Path:
    path = get_config_path()
    path.parent.mkdir(parents=True, exist_ok=True)
    return path


def read_raw_config() -> Optional[str]:
    path = get_config_path()
    if not path.exists():
        return None
    return path.read_text(encoding="utf-8")


def write_config(contents: str) -> None:
    path = ensure_config_dir()
    path.write_text(contents, encoding="utf-8")


def load_config() -> Dict[str, Any]:
    raw = read_raw_config()
    if raw is None:
        return {}

    try:
        return tomllib.loads(raw)
    except Exception as e:
        raise RuntimeError(f"Invalid config.toml: {e}") from e


def get_llm_provider_name(override: Optional[str] = None) -> str:
    if override:
        return override

    cfg = load_config()
    llm = cfg.get("llm", {})

    provider = llm.get("provider")
    if not provider:
        raise RuntimeError("No LLM provider configured.\n" "Run: explainthisrepo init")

    return provider


def get_provider_config(provider: str) -> Dict[str, Any]:
    cfg = load_config()
    providers = cfg.get("providers", {})

    provider_cfg = providers.get(provider)
    if provider_cfg is None:
        return {}

    if not isinstance(provider_cfg, dict):
        raise RuntimeError(f"Invalid config for provider '{provider}'")

    return provider_cfg

from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path

_MAX_DEFAULT_BYTES = 32_000
_SAMPLE_SIZE = 4_096


@dataclass(frozen=True, slots=True)
class FileReadResult:
    path: str
    name: str
    extension: str
    size_bytes: int
    content: str
    is_text: bool


def _text_ratio(value: str) -> float:
    if not value:
        return 1.0

    visible = 0
    for ch in value:
        if ch.isprintable() or ch in "\n\r\t":
            visible += 1
    return visible / len(value)


def _is_probably_binary(sample: bytes) -> bool:
    if not sample:
        return False

    if sample.startswith(
        (
            b"\xef\xbb\xbf",
            b"\xff\xfe",
            b"\xfe\xff",
            b"\xff\xfe\x00\x00",
            b"\x00\x00\xfe\xff",
        )
    ):
        return False

    if b"\x00" in sample:
        for encoding in (
            "utf-16",
            "utf-16-le",
            "utf-16-be",
            "utf-32",
            "utf-32-le",
            "utf-32-be",
        ):
            try:
                decoded = sample.decode(encoding)
            except UnicodeDecodeError:
                continue
            if _text_ratio(decoded) >= 0.7:
                return False
        return True

    control = 0
    for byte in sample:
        if byte in (9, 10, 13, 12, 8):
            continue
        if byte < 32 or byte == 127:
            control += 1

    return control / len(sample) > 0.3


def _decode_text(raw: bytes) -> str:
    encodings = (
        "utf-8",
        "utf-8-sig",
        "utf-16",
        "utf-16-le",
        "utf-16-be",
        "cp1252",
        "latin-1",
    )

    for encoding in encodings:
        try:
            text = raw.decode(encoding)
        except UnicodeDecodeError:
            continue

        if _text_ratio(text) >= 0.6:
            return text

    raise ValueError("file appears to be binary or uses an unsupported text encoding")


def build_file_read_result(
    *,
    path: str,
    raw: bytes,
    size_bytes: int,
    max_bytes: int = _MAX_DEFAULT_BYTES,
) -> FileReadResult:
    if max_bytes <= 0:
        raise ValueError("max_bytes must be greater than 0")

    bounded = raw[:max_bytes]
    sample = bounded[:_SAMPLE_SIZE]

    if _is_probably_binary(sample):
        raise ValueError("binary files are not supported")

    content = _decode_text(bounded)

    file_path = Path(path)
    return FileReadResult(
        path=path,
        name=file_path.name,
        extension=file_path.suffix.lower().lstrip("."),
        size_bytes=size_bytes,
        content=content,
        is_text=True,
    )


def read_local_file(path: str, max_bytes: int = _MAX_DEFAULT_BYTES) -> FileReadResult:
    if max_bytes <= 0:
        raise ValueError("max_bytes must be greater than 0")

    file_path = Path(path).expanduser()

    if not file_path.exists():
        raise FileNotFoundError(f"No such file: {path}")

    if not file_path.is_file():
        raise ValueError(f"Not a file: {path}")

    try:
        size_bytes = file_path.stat().st_size
        with file_path.open("rb") as handle:
            raw = handle.read(max_bytes)
    except OSError as exc:
        raise OSError(f"Could not read file '{path}': {exc}") from exc

    return build_file_read_result(
        path=str(file_path.resolve()),
        raw=raw,
        size_bytes=size_bytes,
        max_bytes=max_bytes,
    )

from explain_this_repo.providers.registry import get_active_provider


def generate_explanation(
    prompt: str,
    provider_override: str | None = None,
) -> str:
    provider = get_active_provider(override=provider_override)

    try:
        output = provider.generate(prompt)
    except Exception as e:
        raise RuntimeError(f"{provider.name} generation failed: {e}") from e

    if not output or not output.strip():
        raise RuntimeError(f"{provider.name} returned no output")

    return output.strip()

from __future__ import annotations

import base64
import binascii
import os
import time
from typing import Optional
from urllib.parse import quote

import requests

from explain_this_repo.config import load_config
from explain_this_repo.file_reader import FileReadResult, build_file_read_result

GITHUB_API_BASE = "https://api.github.com"
_MAX_FILE_BYTES = 32_000


def _get_token(token: Optional[str] = None) -> Optional[str]:
    if token and token.strip():
        return token.strip()

    try:
        cfg = load_config() or {}
        if isinstance(cfg, dict):
            github_cfg = cfg.get("github", {})
            if isinstance(github_cfg, dict):
                cfg_token = github_cfg.get("token")
                if cfg_token and str(cfg_token).strip():
                    return str(cfg_token).strip()
    except Exception:
        pass

    env_token = os.getenv("GITHUB_TOKEN") or os.getenv("GH_TOKEN")
    if env_token and env_token.strip():
        return env_token.strip()

    return None


def _make_session(token: Optional[str] = None) -> requests.Session:
    session = requests.Session()

    headers = {
        "User-Agent": "explainthisrepo/1.0",
        "Accept": "application/vnd.github+json",
    }

    resolved_token = _get_token(token)
    if resolved_token:
        headers["Authorization"] = f"Bearer {resolved_token}"

    session.headers.update(headers)
    return session


def _rate_limit_message(response: requests.Response) -> str:
    remaining = response.headers.get("X-RateLimit-Remaining")
    reset = response.headers.get("X-RateLimit-Reset")

    if remaining == "0" and reset:
        try:
            reset_ts = int(reset)
            wait_s = max(0, reset_ts - int(time.time()))
            mins = (wait_s + 59) // 60
            return (
                "GitHub API rate limit exceeded.\n"
                f"Try again in ~{mins} minute(s).\n"
                "Fix:\n"
                "- Set GITHUB_TOKEN in config or environment\n"
                "- Or run `explainthisrepo init`\n"
            )
        except Exception:
            pass

    return (
        "GitHub API rate limit exceeded.\n"
        "Fix:\n"
        "- Set GITHUB_TOKEN in config or environment\n"
        "- Or run `explainthisrepo init`\n"
    )


def _request_json(
    session: requests.Session,
    url: str,
    *,
    timeout: int = 10,
    retries: int = 4,
) -> dict:
    backoff = 1.5

    for attempt in range(retries + 1):
        try:
            response = session.get(url, timeout=timeout)
        except requests.RequestException as e:
            if attempt == retries:
                raise RuntimeError(f"Network error while calling GitHub: {e}") from e
            time.sleep(backoff)
            backoff *= 2
            continue

        if response.status_code == 200:
            return response.json()

        if response.status_code == 404:
            raise RuntimeError(
                "Repository not found.\n"
                "If this is a private repository, configure GitHub access:\n"
                "- Run `explainthisrepo init`\n"
                "- Or set GITHUB_TOKEN (see https://github.com/calchiwo/ExplainThisRepo/blob/main/docs/GITHUB_TOKEN.md)"
            )

        if response.status_code in (403, 429):
            text_lower = (response.text or "").lower()

            if response.headers.get("X-RateLimit-Remaining") == "0":
                raise RuntimeError(_rate_limit_message(response))

            if "secondary rate limit" in text_lower or "rate limit" in text_lower:
                if attempt == retries:
                    raise RuntimeError(_rate_limit_message(response))
                time.sleep(backoff)
                backoff *= 2
                continue

            if "resource not accessible by integration" in text_lower or "private" in text_lower:
                raise RuntimeError("GitHub API access forbidden (403).")

            if attempt == retries:
                raise RuntimeError("GitHub API access forbidden (403).")

            time.sleep(backoff)
            backoff *= 2
            continue

        if 500 <= response.status_code <= 599:
            if attempt == retries:
                raise RuntimeError(
                    f"GitHub API server error ({response.status_code})."
                )
            time.sleep(backoff)
            backoff *= 2
            continue

        raise RuntimeError(f"GitHub API request failed ({response.status_code}).")

    raise RuntimeError("GitHub request failed unexpectedly.")


def _request_text(
    session: requests.Session,
    url: str,
    *,
    accept: str,
    timeout: int = 10,
    retries: int = 4,
) -> Optional[str]:
    backoff = 1.5

    for attempt in range(retries + 1):
        try:
            response = session.get(url, headers={"Accept": accept}, timeout=timeout)
        except requests.RequestException:
            if attempt == retries:
                return None
            time.sleep(backoff)
            backoff *= 2
            continue

        if response.status_code == 200:
            return response.text

        if response.status_code == 404:
            return None

        if response.status_code in (403, 429):
            text_lower = (response.text or "").lower()

            if response.headers.get("X-RateLimit-Remaining") == "0":
                return None

            if "secondary rate limit" in text_lower or "rate limit" in text_lower:
                if attempt == retries:
                    return None
                time.sleep(backoff)
                backoff *= 2
                continue

            if "resource not accessible by integration" in text_lower or "private" in text_lower:
                return None

            if attempt == retries:
                return None

            time.sleep(backoff)
            backoff *= 2
            continue

        if 500 <= response.status_code <= 599:
            if attempt == retries:
                return None
            time.sleep(backoff)
            backoff *= 2
            continue

        return None

    return None


def _normalize_github_path(file_path: str) -> str:
    cleaned = file_path.strip()

    while cleaned.startswith("./"):
        cleaned = cleaned[2:]

    cleaned = cleaned.replace("\\", "/")

    while "//" in cleaned:
        cleaned = cleaned.replace("//", "/")

    cleaned = cleaned.strip("/")

    if not cleaned:
        raise RuntimeError("GitHub file path is empty.")

    return cleaned


def _quote_github_path(file_path: str) -> str:
    return quote(file_path, safe="/")


def _decode_base64_content(content: str) -> bytes:
    cleaned = "".join(content.split())
    if not cleaned:
        return b""

    pad = (-len(cleaned)) % 4
    if pad:
        cleaned += "=" * pad

    try:
        return base64.b64decode(cleaned, validate=True)
    except (ValueError, binascii.Error) as e:
        raise RuntimeError("Failed to decode GitHub base64 file content.") from e


def _request_contents_json(
    session: requests.Session,
    url: str,
    *,
    owner: str,
    repo: str,
    path: str,
    timeout: int = 10,
    retries: int = 4,
) -> object:
    backoff = 1.5

    for attempt in range(retries + 1):
        try:
            response = session.get(url, timeout=timeout)
        except requests.RequestException as e:
            if attempt == retries:
                raise RuntimeError(f"Network error while calling GitHub: {e}") from e
            time.sleep(backoff)
            backoff *= 2
            continue

        if response.status_code == 200:
            return response.json()

        if response.status_code == 404:
            raise RuntimeError(f"GitHub 404: {owner}/{repo}/{path} not found.")

        if response.status_code in (403, 429):
            text_lower = (response.text or "").lower()

            if response.headers.get("X-RateLimit-Remaining") == "0":
                raise RuntimeError(_rate_limit_message(response))

            if "secondary rate limit" in text_lower or "rate limit" in text_lower:
                if attempt == retries:
                    raise RuntimeError(_rate_limit_message(response))
                time.sleep(backoff)
                backoff *= 2
                continue

            if "resource not accessible by integration" in text_lower or "private" in text_lower:
                raise RuntimeError(
                    f"GitHub API access forbidden (403) for {owner}/{repo}/{path}.\n"
                    "If this is a private repository, check your GitHub token permissions."
                )

            if attempt == retries:
                raise RuntimeError(
                    f"GitHub API access forbidden (403) for {owner}/{repo}/{path}."
                )

            time.sleep(backoff)
            backoff *= 2
            continue

        if 500 <= response.status_code <= 599:
            if attempt == retries:
                raise RuntimeError(
                    f"GitHub API server error ({response.status_code}) while fetching {owner}/{repo}/{path}."
                )
            time.sleep(backoff)
            backoff *= 2
            continue

        raise RuntimeError(
            f"GitHub API request failed ({response.status_code}) while fetching {owner}/{repo}/{path}."
        )

    raise RuntimeError("GitHub request failed unexpectedly.")


def fetch_repo(owner: str, repo: str, token: Optional[str] = None) -> dict:
    session = _make_session(token)
    url = f"{GITHUB_API_BASE}/repos/{owner}/{repo}"
    return _request_json(session, url)


def fetch_readme(owner: str, repo: str, token: Optional[str] = None) -> str | None:
    session = _make_session(token)

    api_url = f"{GITHUB_API_BASE}/repos/{owner}/{repo}/readme"
    text = _request_text(
        session,
        api_url,
        accept="application/vnd.github.v3.raw",
    )
    if text:
        return text

    branches = ["main", "master"]
    filenames = ["README.md", "readme.md", "README.MD"]

    for branch in branches:
        for name in filenames:
            raw_url = f"https://raw.githubusercontent.com/{owner}/{repo}/{branch}/{name}"
            raw = _request_text(
                session,
                raw_url,
                accept="text/plain",
                timeout=10,
                retries=2,
            )
            if raw:
                return raw

    return None


def fetch_tree(owner: str, repo: str, token: Optional[str] = None) -> list[dict]:
    session = _make_session(token)
    repo_meta = fetch_repo(owner, repo, token=token)
    branch = repo_meta.get("default_branch") or "main"

    url = f"{GITHUB_API_BASE}/repos/{owner}/{repo}/git/trees/{branch}?recursive=1"
    data = _request_json(session, url)

    tree = data.get("tree", [])
    if not isinstance(tree, list):
        return []
    return tree


def fetch_file(
    owner: str,
    repo: str,
    file_path: str,
    token: Optional[str] = None,
) -> str | None:
    session = _make_session(token)
    url = f"{GITHUB_API_BASE}/repos/{owner}/{repo}/contents/{file_path}"
    return _request_text(
        session,
        url,
        accept="application/vnd.github.v3.raw",
        timeout=10,
        retries=2,
    )


def fetch_file_result(
    owner: str,
    repo: str,
    file_path: str,
    token: Optional[str] = None,
    max_bytes: int = _MAX_FILE_BYTES,
) -> FileReadResult:
    normalized_path = _normalize_github_path(file_path)
    session = _make_session(token)
    url = f"{GITHUB_API_BASE}/repos/{owner}/{repo}/contents/{_quote_github_path(normalized_path)}"

    payload = _request_contents_json(
        session,
        url,
        owner=owner,
        repo=repo,
        path=normalized_path,
    )

    if isinstance(payload, list):
        raise RuntimeError(
            f"GitHub path resolves to a directory, not a file: {owner}/{repo}/{normalized_path}"
        )

    if not isinstance(payload, dict):
        raise RuntimeError(
            f"GitHub API returned unexpected data for {owner}/{repo}/{normalized_path}."
        )

    entry_type = str(payload.get("type") or "").lower()
    if entry_type != "file":
        raise RuntimeError(
            f"GitHub path does not resolve to a regular file: {owner}/{repo}/{normalized_path}"
        )

    encoding = str(payload.get("encoding") or "").lower()
    if encoding != "base64":
        raise RuntimeError(
            f"GitHub file encoding is unsupported for {owner}/{repo}/{normalized_path}."
        )

    content_field = payload.get("content")
    if not isinstance(content_field, str) or not content_field.strip():
        raise RuntimeError(
            f"GitHub file content is unavailable for {owner}/{repo}/{normalized_path}."
        )

    raw = _decode_base64_content(content_field)

    size_value = payload.get("size")
    try:
        size_bytes = int(size_value) if size_value is not None else len(raw)
    except Exception:
        size_bytes = len(raw)

    return build_file_read_result(
        path=normalized_path,
        raw=raw,
        size_bytes=size_bytes,
        max_bytes=max_bytes,
    )


def fetch_directory_contents(
    owner: str,
    repo: str,
    directory_path: str,
    token: Optional[str] = None,
) -> list[dict]:
    normalized_path = _normalize_github_path(directory_path)
    session = _make_session(token)
    url = f"{GITHUB_API_BASE}/repos/{owner}/{repo}/contents/{_quote_github_path(normalized_path)}"

    payload = _request_contents_json(
        session,
        url,
        owner=owner,
        repo=repo,
        path=normalized_path,
    )

    if isinstance(payload, dict):
        entry_type = str(payload.get("type") or "").lower()
        if entry_type == "file":
            raise RuntimeError(
                f"GitHub path resolves to a file, not a directory: {owner}/{repo}/{normalized_path}"
            )
        raise RuntimeError(
            f"GitHub path does not resolve to a directory: {owner}/{repo}/{normalized_path}"
        )

    if not isinstance(payload, list):
        raise RuntimeError(
            f"GitHub API returned unexpected data for {owner}/{repo}/{normalized_path}."
        )

    directory_items: list[dict] = []
    for item in payload:
        if not isinstance(item, dict):
            raise RuntimeError(
                f"GitHub directory listing contains unexpected data for {owner}/{repo}/{normalized_path}."
            )
        directory_items.append(item)

    return directory_items


def fetch_languages(owner: str, repo: str, token: Optional[str] = None) -> dict:
    session = _make_session(token)
    url = f"{GITHUB_API_BASE}/repos/{owner}/{repo}/languages"
    return _request_json(session, url)

import getpass
from typing import Dict

from rich.console import Console

from explain_this_repo.config import write_config

err = Console(stderr=True)

PROVIDERS = {
    "1": "gemini",
    "2": "openai",
    "3": "ollama",
    "4": "anthropic",
    "5": "groq",
    "6": "openrouter",
}


def _prompt_provider() -> str:
    import sys
    import readchar

    options = [
        "1) Gemini",
        "2) OpenAI",
        "3) Ollama (local or cloud-routed)",
        "4) Anthropic (Claude)",
        "5) Groq",
        "6) OpenRouter",
    ]

    err.print("Select LLM provider:", style="bold")
    err.print()

    for opt in options:
        err.print(f"  {opt}")

    err.print(" >", end="")

    index = None

    total_option_lines = len(options)

    def goto_option(i):
        sys.stdout.write(f"\033[{total_option_lines - i}A")

    def back_to_prompt(i):
        sys.stdout.write(f"\033[{total_option_lines - i}B")

    def clear_line():
        sys.stdout.write("\033[2K\r")

    def set_line(i, selected):
        goto_option(i)
        clear_line()
        if selected:
            sys.stdout.write(f"> {options[i]}")
        else:
            sys.stdout.write(f"  {options[i]}")
        back_to_prompt(i)
        sys.stdout.flush()

    while True:
        key = readchar.readkey()

        if key in (readchar.key.UP, readchar.key.DOWN):
            if index is None:
                # enter navigation mode
                index = len(options) - 1 if key == readchar.key.UP else 0
                set_line(index, True)
            else:
                prev = index

                if key == readchar.key.UP:
                    if index == 0:
                        set_line(index, False)
                        index = None
                        continue
                    index -= 1
                else:
                    if index == len(options) - 1:
                        set_line(index, False)
                        index = None
                        continue
                    index += 1

                set_line(prev, False)
                set_line(index, True)

        elif key == readchar.key.ENTER:
            if index is not None:
                print()
                return PROVIDERS[str(index + 1)]
            else:
                choice = input().strip()
                provider = PROVIDERS.get(choice)
                if not provider:
                    err.print("error: invalid provider selection", style="red")
                    raise SystemExit(1)
                return provider

        elif key.isdigit():
            sys.stdout.write(key)
            sys.stdout.flush()
            choice = key + input().strip()
            provider = PROVIDERS.get(choice)
            if not provider:
                err.print("error: invalid provider selection", style="red")
                raise SystemExit(1)
            return provider


def _prompt_provider_config(provider: str) -> Dict[str, str]:
    if provider == "gemini":
        key = getpass.getpass("Gemini API key: ").strip()
        if not key:
            raise RuntimeError("API key cannot be empty")
        return {"api_key": key}

    if provider == "openai":
        key = getpass.getpass("OpenAI API key: ").strip()
        if not key:
            raise RuntimeError("API key cannot be empty")
        return {"api_key": key}

    if provider == "ollama":
        model = input("Ollama model (e.g. llama3, glm-5:cloud, gemma3:4b): ").strip()
        if not model:
            raise RuntimeError("Model cannot be empty")

        host = (
            input("Ollama host [http://localhost:11434]: ").strip()
            or "http://localhost:11434"
        )

        return {
            "model": model,
            "host": host,
        }

    if provider == "anthropic":
        key = getpass.getpass("Anthropic (Claude) API key: ").strip()
        if not key:
            raise RuntimeError("API key cannot be empty")
        return {"api_key": key}

    if provider == "groq":
        key = getpass.getpass("Groq API key: ").strip()
        if not key:
            raise RuntimeError("API key cannot be empty")

        err.print("Select Groq model:", style="bold")
        err.print("  1) llama3-70b-8192")
        err.print("  2) mixtral-8x7b")
        err.print("  3) deepseek-r1-distill-llama-70b")

        choice = input("> ").strip()

        model_map = {
            "1": "llama3-70b-8192",
            "2": "mixtral-8x7b",
            "3": "deepseek-r1-distill-llama-70b",
        }

        model = model_map.get(choice)
        if not model:
            raise RuntimeError("Invalid model selection")

        return {
            "api_key": key,
            "model": model,
        }

    if provider == "openrouter":
        key = getpass.getpass("OpenRouter API key: ").strip()
        if not key:
            raise RuntimeError("API key cannot be empty")

        err.print("Select OpenRouter model:", style="bold")
        err.print("  1) openai/gpt-4o (balanced)")
        err.print("  2) anthropic/claude-3.5-sonnet (reasoning)")
        err.print("  3) meta-llama/llama-3-70b-instruct (open)")
        err.print("  4) deepseek/deepseek-chat (cheap/fast)")
        err.print("  5) Enter model manually")

        choice = input("> ").strip()

        model_map = {
            "1": "openai/gpt-4o",
            "2": "anthropic/claude-3.5-sonnet",
            "3": "meta-llama/llama-3-70b-instruct",
            "4": "deepseek/deepseek-chat",
        }

        if choice == "5":
            model = input("Enter model (provider/model): ").strip()
            if not model:
                raise RuntimeError("Model cannot be empty")
        else:
            model = model_map.get(choice)
            if not model:
                raise RuntimeError("Invalid model selection")

        return {
            "api_key": key,
            "model": model,
        }

    raise RuntimeError(f"Unsupported provider: {provider}")


def _prompt_github_token() -> Dict[str, str]:
    err.print(
        "\nConfigure GitHub access for private repos and higher rate limits:",
        style="cyan",
    )
    token = getpass.getpass("GitHub token (leave empty to skip): ").strip()
    if not token:
        return {}
    return {"token": token}


def run_init() -> None:
    err.print(
        "WARNING: input is hidden where applicable. Configuration will be written once.",
        style="yellow",
    )

    try:
        provider = _prompt_provider()
        provider_cfg = _prompt_provider_config(provider)
        github_cfg = _prompt_github_token()
    except KeyboardInterrupt:
        err.print("\nInterrupted.", style="red")
        raise SystemExit(130)
    except Exception as e:
        err.print(f"error: {e}", style="red")
        raise SystemExit(1)

    lines = [
        "[llm]",
        f'provider = "{provider}"',
        "",
        f"[providers.{provider}]",
    ]

    for k, v in provider_cfg.items():
        lines.append(f'{k} = "{v}"')

    if github_cfg:
        lines.extend(
            [
                "",
                "[github]",
            ]
        )
        for k, v in github_cfg.items():
            lines.append(f'{k} = "{v}"')

    contents = "\n".join(lines) + "\n"

    write_config(contents)

    err.print("Configuration written.", style="green")

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any, Optional

from explain_this_repo.github import fetch_file, fetch_tree


@dataclass
class ReadResult:
    tree: list[dict]
    tree_text: str
    files_text: str
    key_files: dict[str, str] = field(default_factory=dict)


MAX_FILES = 20
MAX_TOTAL_CHARS = 150_000
MAX_FILE_CHARS = 8000


def _is_noise_file(path: str) -> bool:
    p = path.lower()
    if p.endswith((".png", ".jpg", ".jpeg", ".gif", ".svg", ".ico", ".webp")):
        return True
    if p.endswith((".mp4", ".mov", ".avi", ".mkv")):
        return True
    if p.endswith((".zip", ".tar", ".gz", ".7z", ".rar")):
        return True
    if p.endswith((".lock", ".min.js", ".min.css")):
        return True
    if "/dist/" in f"/{p}/" or "/build/" in f"/{p}/" or "/.git/" in f"/{p}/":
        return True
    if p.startswith("dist/") or p.startswith("build/"):
        return True
    return False


def _score_path(path: str) -> int:
    p = path.lower()

    if p in {"package.json", "pyproject.toml", "requirements.txt", "setup.py"}:
        return 100
    if p in {"readme.md", "readme"}:
        return 90

    if p.endswith(("main.py", "__main__.py", "cli.py", "cli.ts", "cli.js")):
        return 85
    if p.endswith(
        ("index.js", "index.ts", "app.js", "app.ts", "server.js", "server.ts")
    ):
        return 80

    if p in {"dockerfile", "compose.yml", "docker-compose.yml"}:
        return 75
    if p.endswith(("tsconfig.json", "vite.config.ts", "next.config.js", "vercel.json")):
        return 70

    if p.startswith(("src/", "app/", "apps/", "packages/", "lib/", "api/")):
        return 60

    if p.startswith(("tests/", "test/")):
        return 40

    return 10


def _render_tree(tree: list[dict[str, Any]], max_lines: int = 160) -> str:
    paths = []
    for item in tree:
        if item.get("type") != "blob":
            continue
        path = item.get("path")
        if not path:
            continue
        if _is_noise_file(path):
            continue
        paths.append(path)

    paths = sorted(paths)[:max_lines]
    if not paths:
        return "No tree provided"

    return "\n".join(paths)


def _pick_signal_files(tree: list[dict[str, Any]]) -> list[str]:
    candidates = []
    for item in tree:
        if item.get("type") != "blob":
            continue
        path = item.get("path")
        if not path:
            continue
        if _is_noise_file(path):
            continue
        candidates.append(path)

    candidates.sort(key=_score_path, reverse=True)

    picked = []
    seen = set()
    for p in candidates:
        if p in seen:
            continue
        seen.add(p)
        picked.append(p)
        if len(picked) >= MAX_FILES:
            break

    return picked


def _format_files_snippets(snips: list[tuple[str, str]]) -> str:
    if not snips:
        return "No code files provided"

    out = []
    for path, content in snips:
        out.append(f"\n=== {path} ===\n{content.strip()}\n")
    return "\n".join(out).strip()


def read_repo_signal_files(
    owner: str,
    repo: str,
    token: Optional[str] = None,
) -> ReadResult:
    key_files: dict[str, str] = {}

    # token flows here
    tree = fetch_tree(owner, repo, token=token)

    tree_text = _render_tree(tree)
    picked = _pick_signal_files(tree)

    total = 0
    snippets: list[tuple[str, str]] = []

    for p in picked:
        if total >= MAX_TOTAL_CHARS:
            break

        content = fetch_file(owner, repo, p, token=token)
        if not content:
            continue

        snippet = content[:MAX_FILE_CHARS]
        total += len(snippet)
        snippets.append((p, snippet))

        if len(snippets) >= MAX_FILES:
            break

    files_text = _format_files_snippets(snippets)

    return ReadResult(
        tree=tree,
        tree_text=tree_text,
        files_text=files_text,
        key_files=key_files,
    )

from __future__ import annotations

from typing import Any, Dict, List

StackReport = Dict[str, List[str]]


def detect_stack(
    languages: Dict[str, int],
    tree: list[dict[str, Any] | str],
    key_files: Dict[str, str],
) -> StackReport:
    report: StackReport = {
        "languages": [],
        "runtimes": [],
        "frameworks": [],
        "databases": [],
        "tooling": [],
        "infra": [],
        "package_managers": [],
    }

    # Languages (from GitHub languages API)
    report["languages"] = sorted(languages.keys())

    # --- Package managers ---
    paths = {
        item.lower() if isinstance(item, str) else item.get("path", "").lower()
        for item in tree
    }

    if "pnpm-lock.yaml" in paths:
        report["package_managers"].append("pnpm")
    elif "yarn.lock" in paths:
        report["package_managers"].append("yarn")
    elif "package-lock.json" in paths:
        report["package_managers"].append("npm")

    if "requirements.txt" in paths or "pyproject.toml" in paths:
        report["package_managers"].append("pip")

    # --- Infra ---
    if "dockerfile" in paths:
        report["infra"].append("Docker")
    if "docker-compose.yml" in paths:
        report["infra"].append("Docker Compose")
    if any(p.startswith(".github/workflows") for p in paths):
        report["infra"].append("GitHub Actions")
    if "vercel.json" in paths:
        report["infra"].append("Vercel")

    # --- Frameworks from package.json ---
    pkg = key_files.get("package.json")
    if pkg:
        import json

        try:
            data = json.loads(pkg)
            deps = {**data.get("dependencies", {}), **data.get("devDependencies", {})}
        except Exception:
            deps = {}

        def has(name: str) -> bool:
            return name in deps

        if has("react"):
            report["frameworks"].append("React")
        if has("next"):
            report["frameworks"].append("Next.js")
        if has("express"):
            report["frameworks"].append("Express")
        if has("vue"):
            report["frameworks"].append("Vue")
        if has("django"):
            report["frameworks"].append("Django")
        if has("fastapi"):
            report["frameworks"].append("FastAPI")

        if has("prisma"):
            report["databases"].append("Prisma")
        if has("mongoose"):
            report["databases"].append("MongoDB")

        if has("jest"):
            report["tooling"].append("Jest")
        if has("eslint"):
            report["tooling"].append("ESLint")

    return report

