class GroqProvider(LLMProvider):
    name = "groq"

    def __init__(self, config: Dict[str, Any]) -> None:
        self.config = config
        self.api_key = config.get("api_key")
        self.model = config.get("model")
        self._client = None

        self.validate_config()

    def validate_config(self) -> None:
        if not self.api_key or not str(self.api_key).strip():
            raise LLMProviderError(
                "Groq provider requires an API key.\n"
                "Run `explainthisrepo init` or set providers.groq.api_key."
            )

        if not self.model or not str(self.model).strip():
            raise LLMProviderError(
                "Groq provider requires a model.\n"
                "Set providers.groq.model (e.g. llama3-70b-8192, mixtral-8x7b, deepseek-r1-distill-llama-70b)."
            )

    def _get_client(self):
        if self._client is not None:
            return self._client

        try:
            from groq import Groq
        except ImportError as e:
            raise LLMProviderError(
                "Groq support is not installed.\n"
                "Install it with:\n"
                '  pip install "explainthisrepo[groq]"'
            ) from e

        self._client = Groq(api_key=self.api_key)
        return self._client

    def generate(self, prompt: str) -> str:
        client = self._get_client()

        try:
            response = client.chat.completions.create(
                model=self.model,
                messages=[{"role": "user", "content": prompt}],
            )
        except Exception as e:
            raise LLMProviderError(f"Groq request failed: {e}") from e

        try:
            text = response.choices[0].message.content
        except Exception:
            text = None

        if not text or not text.strip():
            raise LLMProviderError("Groq returned no text")

        return text.strip()

    def doctor(self) -> list[str]:
        return [
            f"GROQ_API_KEY set: {bool(self.api_key)}",
            f"model: {self.model}",
        ]

from __future__ import annotations

import json
import urllib.error
import urllib.request
from typing import Any, Dict

from explain_this_repo.providers.base import LLMProvider, LLMProviderError

DEFAULT_HOST = "http://localhost:11434"


class OllamaProvider(LLMProvider):
    name = "ollama"

    def __init__(self, config: Dict[str, Any]) -> None:
        self.model = config.get("model")
        self.host = (config.get("host") or DEFAULT_HOST).rstrip("/")

        self.validate_config()

    def validate_config(self) -> None:
        if not self.model or not str(self.model).strip():
            raise LLMProviderError(
                "Ollama provider requires a model.\n"
                "Set providers.ollama.model (e.g. llama3, gemma3:4b, glm-5:cloud)."
            )

        if not self.host.startswith("http"):
            raise LLMProviderError(
                "Ollama host must be a valid URL (e.g. http://localhost:11434)"
            )

    def doctor(self) -> list[str]:
        results = []

        url = f"{self.host}/api/tags"

        try:
            req = urllib.request.Request(url, method="GET")
            with urllib.request.urlopen(req, timeout=5) as response:
                if response.status == 200:
                    results.append("Ollama server reachable")
                else:
                    results.append(f"Ollama server responded with {response.status}")
        except urllib.error.URLError as e:
            results.append(f"Ollama server not reachable: {e}")
        except Exception as e:
            results.append(f"Ollama check failed: {e}")

        results.append(f"model: {self.model}")
        results.append(f"host: {self.host}")

        return results

    def generate(self, prompt: str) -> str:
        url = f"{self.host}/api/generate"

        payload = {
            "model": self.model,
            "prompt": prompt,
            "stream": False,
        }

        req = urllib.request.Request(
            url,
            data=json.dumps(payload).encode("utf-8"),
            headers={"Content-Type": "application/json"},
            method="POST",
        )

        try:
            with urllib.request.urlopen(req, timeout=120) as response:
                raw = response.read().decode("utf-8")
        except urllib.error.HTTPError as e:
            raise LLMProviderError(f"Ollama HTTP error: {e.code} {e.reason}") from e
        except urllib.error.URLError as e:
            raise LLMProviderError(
                "Failed to connect to Ollama.\n"
                "Ensure Ollama is running locally.\n"
                "Start it with: ollama serve"
            ) from e
        except Exception as e:
            raise LLMProviderError(f"Ollama request failed: {e}") from e

        try:
            data = json.loads(raw)
        except Exception as e:
            raise LLMProviderError("Invalid response from Ollama") from e

        text = data.get("response")
        if not text or not text.strip():
            raise LLMProviderError("Ollama returned no text")

        return text.strip()

