import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { parse } from "@iarna/toml";

const CONFIG_DIR_NAME = "ExplainThisRepo";
const CONFIG_FILE_NAME = "config.toml";

export function getConfigPath(): string {
  if (process.platform === "win32") {
    const appdata = process.env.APPDATA;
    if (!appdata) {
      throw new Error("APPDATA environment variable is not set");
    }
    return path.join(appdata, CONFIG_DIR_NAME, CONFIG_FILE_NAME);
  }

  const xdg = process.env.XDG_CONFIG_HOME;
  const base = xdg ?? path.join(os.homedir(), ".config");
  return path.join(base, "explainthisrepo", CONFIG_FILE_NAME);
}

export function ensureConfigDir(): string {
  const configPath = getConfigPath();
  const dir = path.dirname(configPath);
  fs.mkdirSync(dir, { recursive: true });
  return configPath;
}

export function writeConfig(contents: string): void {
  const path = ensureConfigDir();
  fs.writeFileSync(path, contents, { encoding: "utf-8" });
}

export function readConfig(): string | null {
  const path = getConfigPath();
  if (!fs.existsSync(path)) return null;
  return fs.readFileSync(path, "utf-8");
}

export function loadConfig(): any {
  const raw = readConfig();

  if (!raw) {
    return {};
  }

  try {
    return parse(raw);
  } catch (err) {
    throw new Error("Invalid config.toml format");
  }
}

import { getActiveProvider } from "./providers/registry.js"

export async function generateExplanation(
  prompt: string,
  providerOverride?: string
): Promise<string> {

  const provider = getActiveProvider(providerOverride)

  try {

    const output = await provider.generate(prompt)

    if (!output || !output.trim()) {
      throw new Error(`${provider.name} returned no output`)
    }

    return output.trim()

  } catch (err: any) {

    const message =
      err?.message ? String(err.message) : String(err)

    throw new Error(
      `${provider.name} generation failed: ${message}`
    )

  }

}

import axios, { AxiosInstance } from "axios";
import { loadConfig } from "./config.js";

const GITHUB_API_BASE = "https://api.github.com";

export type RepoLanguageMap = Record<string, number>;

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function asNonEmptyString(value: unknown): string | null {
  if (typeof value !== "string") {
    return null;
  }

  const trimmed = value.trim();
  return trimmed ? trimmed : null;
}

function getGithubToken(overrideToken?: string): string | null {
  const direct = asNonEmptyString(overrideToken);
  if (direct) {
    return direct;
  }

  try {
    const cfg = (loadConfig() ?? {}) as Record<string, any>;
    const githubCfg = cfg.github as Record<string, any> | undefined;
    const configToken = asNonEmptyString(githubCfg?.token);
    if (configToken) {
      return configToken;
    }
  } catch {
    // Ignore config read errors and fall back to env
  }

  const envToken = asNonEmptyString(
    process.env.GITHUB_TOKEN || process.env.GH_TOKEN,
  );
  if (envToken) {
    return envToken;
  }

  return null;
}

function createGithubClient(token?: string): AxiosInstance {
  const headers: Record<string, string> = {
    Accept: "application/vnd.github+json",
    "User-Agent": "explainthisrepo/1.0",
  };

  const resolvedToken = getGithubToken(token);
  if (resolvedToken) {
    headers.Authorization = `Bearer ${resolvedToken}`;
  }

  return axios.create({
    baseURL: GITHUB_API_BASE,
    headers,
    timeout: 10_000,
  });
}

function isRateLimitText(text: unknown): boolean {
  const lower = typeof text === "string" ? text.toLowerCase() : "";
  return (
    lower.includes("secondary rate limit") ||
    lower.includes("rate limit")
  );
}

function rateLimitMessage(response?: { headers?: Record<string, unknown> }): string {
  const reset = response?.headers?.["x-ratelimit-reset"];

  if (typeof reset === "string" || typeof reset === "number") {
    const resetTs = Number(reset);
    if (!Number.isNaN(resetTs)) {
      const waitSeconds = Math.max(0, resetTs * 1000 - Date.now()) / 1000;
      const mins = Math.max(1, Math.ceil(waitSeconds / 60));

      return (
        "GitHub API rate limit exceeded.\n" +
        `Try again in ~${mins} minute(s).\n` +
        "Fix:\n" +
        "- Set GITHUB_TOKEN in config or environment\n" +
        "- Or run `explainthisrepo init`\n"
      );
    }
  }

  return (
    "GitHub API rate limit exceeded.\n" +
    "Fix:\n" +
    "- Set GITHUB_TOKEN in config or environment\n" +
    "- Or run `explainthisrepo init`\n"
  );
}

function privateRepoMessage(): string {
  return (
    "Repository not found.\n" +
    "If this is a private repository, configure GitHub access:\n" +
    "- Run `explainthisrepo init`\n" +
    "- Or set GITHUB_TOKEN (see docs/GITHUB_TOKEN.md)\n"
  );
}

function formatJsonError(err: unknown): string {
  if (!axios.isAxiosError(err)) {
    return `GitHub request failed: ${String(err)}`;
  }

  const status = err.response?.status;
  const data = err.response?.data as any;
  const message = typeof data?.message === "string" ? data.message : err.message;

  if (status === 404) {
    return privateRepoMessage();
  }

  if (status === 401) {
    return "GitHub auth failed (401). Invalid GitHub token.";
  }

  if (status === 403) {
    if (
      err.response?.headers?.["x-ratelimit-remaining"] === "0" ||
      isRateLimitText(message)
    ) {
      return rateLimitMessage(err.response);
    }
    return "GitHub API access forbidden (403).";
  }

  if (status === 429) {
    return rateLimitMessage(err.response);
  }

  if (status && status >= 500) {
    return `GitHub API server error (${status}). Try again later.`;
  }

  if (status !== undefined) {
    return `GitHub API request failed (${status}): ${message}`;
  }

  return `Network error while calling GitHub: ${message}`;
}

async function requestJson<T>(
  client: AxiosInstance,
  url: string,
  opts?: { params?: Record<string, unknown>; maxRetries?: number; baseDelayMs?: number },
): Promise<T> {
  const maxRetries = opts?.maxRetries ?? 4;
  const baseDelayMs = opts?.baseDelayMs ?? 700;

  let attempt = 0;
  let backoff = baseDelayMs;

  while (attempt <= maxRetries) {
    try {
      const response = await client.get<T>(url, {
        params: opts?.params,
      });
      return response.data;
    } catch (err: unknown) {
      if (!axios.isAxiosError(err)) {
        if (attempt >= maxRetries) {
          throw new Error(`Network error while calling GitHub: ${String(err)}`);
        }
        await sleep(backoff);
        backoff *= 2;
        attempt += 1;
        continue;
      }

      const status = err.response?.status;
      const data = err.response?.data as any;
      const message = typeof data?.message === "string" ? data.message : err.message;
      const remaining = err.response?.headers?.["x-ratelimit-remaining"];

      if (status === 404) {
        throw new Error(privateRepoMessage());
      }

      if (status === 403 || status === 429) {
        const rateLimited = remaining === "0" || isRateLimitText(message);

        if (rateLimited) {
          if (attempt >= maxRetries) {
            throw new Error(rateLimitMessage(err.response));
          }
          await sleep(backoff);
          backoff *= 2;
          attempt += 1;
          continue;
        }

        if (status === 429) {
          if (attempt >= maxRetries) {
            throw new Error(rateLimitMessage(err.response));
          }
          await sleep(backoff);
          backoff *= 2;
          attempt += 1;
          continue;
        }

        throw new Error("GitHub API access forbidden (403).");
      }

      if (status && status >= 500) {
        if (attempt >= maxRetries) {
          throw new Error(
            `GitHub API server error (${status}). Try again later.`,
          );
        }
        await sleep(backoff);
        backoff *= 2;
        attempt += 1;
        continue;
      }

      if (status === undefined) {
        if (attempt >= maxRetries) {
          throw new Error(`Network error while calling GitHub: ${message}`);
        }
        await sleep(backoff);
        backoff *= 2;
        attempt += 1;
        continue;
      }

      throw new Error(formatJsonError(err));
    }
  }

  throw new Error("GitHub request failed unexpectedly.");
}

async function requestText(
  client: AxiosInstance,
  url: string,
  opts?: { accept?: string; maxRetries?: number; baseDelayMs?: number; params?: Record<string, unknown> },
): Promise<string | null> {
  const accept = opts?.accept ?? "application/vnd.github.v3.raw";
  const maxRetries = opts?.maxRetries ?? 4;
  const baseDelayMs = opts?.baseDelayMs ?? 700;

  let attempt = 0;
  let backoff = baseDelayMs;

  while (attempt <= maxRetries) {
    try {
      const response = await client.get<string>(url, {
        params: opts?.params,
        headers: { Accept: accept },
        responseType: "text",
        transformResponse: [(data) => data],
      });

      return typeof response.data === "string" ? response.data : String(response.data ?? "");
    } catch (err: unknown) {
      if (!axios.isAxiosError(err)) {
        if (attempt >= maxRetries) {
          return null;
        }
        await sleep(backoff);
        backoff *= 2;
        attempt += 1;
        continue;
      }

      const status = err.response?.status;
      const data = err.response?.data as any;
      const message = typeof data?.message === "string" ? data.message : err.message;
      const remaining = err.response?.headers?.["x-ratelimit-remaining"];

      if (status === 404) {
        return null;
      }

      if (status === 403 || status === 429) {
        const rateLimited = remaining === "0" || isRateLimitText(message);

        if (rateLimited) {
          if (attempt >= maxRetries) {
            return null;
          }
          await sleep(backoff);
          backoff *= 2;
          attempt += 1;
          continue;
        }

        return null;
      }

      if (status && status >= 500) {
        if (attempt >= maxRetries) {
          return null;
        }
        await sleep(backoff);
        backoff *= 2;
        attempt += 1;
        continue;
      }

      return null;
    }
  }

  return null;
}

export async function fetchRepo(owner: string, repo: string, token?: string): Promise<any> {
  const client = createGithubClient(token);
  return requestJson<any>(client, `/repos/${owner}/${repo}`);
}

export async function fetchReadme(
  owner: string,
  repo: string,
  token?: string,
): Promise<string | null> {
  const client = createGithubClient(token);

  const apiUrl = `/repos/${owner}/${repo}/readme`;
  const text = await requestText(client, apiUrl, {
    accept: "application/vnd.github.v3.raw",
    maxRetries: 4,
  });

  if (text) {
    return text;
  }

  const branches = ["main", "master"];
  const filenames = ["README.md", "readme.md", "README.MD"];

  for (const branch of branches) {
    for (const name of filenames) {
      const rawUrl = `https://raw.githubusercontent.com/${owner}/${repo}/${branch}/${name}`;
      const raw = await requestText(client, rawUrl, {
        accept: "text/plain",
        maxRetries: 2,
      });

      if (raw) {
        return raw;
      }
    }
  }

  return null;
}

export async function fetchTree(
  owner: string,
  repo: string,
  token?: string,
): Promise<any[]> {
  const client = createGithubClient(token);

  const repoMeta = await fetchRepo(owner, repo, token);
  const defaultBranch = repoMeta?.default_branch || "main";

  const data = await requestJson<any>(
    client,
    `/repos/${owner}/${repo}/git/trees/${defaultBranch}`,
    { params: { recursive: 1 } },
  );

  const tree = data?.tree || [];
  if (!Array.isArray(tree)) {
    return [];
  }

  // Kept in the current shape to avoid breaking downstream callers.
  return tree.map((item: any) => ({
    path: item.path,
    type: item.type,
    size: item.size,
  }));
}

export async function fetchFile(
  owner: string,
  repo: string,
  filePath: string,
  token?: string,
): Promise<string | null> {
  const client = createGithubClient(token);

  return requestText(client, `/repos/${owner}/${repo}/contents/${filePath}`, {
    accept: "application/vnd.github.v3.raw",
    maxRetries: 2,
  });
}

export async function fetchLanguages(
  owner: string,
  repo: string,
  token?: string,
): Promise<RepoLanguageMap> {
  const client = createGithubClient(token);
  return requestJson<RepoLanguageMap>(client, `/repos/${owner}/${repo}/languages`);
}

import readline, { Interface as ReadlineInterface } from "node:readline";
import process from "node:process";
import chalk from "chalk";

import { writeConfig } from "./config.js";

interface HiddenReadlineInterface extends ReadlineInterface {
  _writeToOutput: (stringToWrite: string) => void;
}

const PROVIDERS: Record<string, string> = {
  "1": "gemini",
  "2": "openai",
  "3": "ollama",
  "4": "anthropic",
  "5": "groq",
  "6": "openrouter",
};

export async function runInit(): Promise<void> {
  const err = process.stderr;

  err.write(
    chalk.yellow(
      "WARNING: input is hidden where applicable. Configuration will be written once.\n",
    ),
  );

  try {
    const provider = await promptProvider();
    const providerConfig = await promptProviderConfig(provider);
    const githubToken = await promptGithubToken();

    const lines: string[] = [
      "[llm]",
      `provider = "${provider}"`,
      "",
      `[providers.${provider}]`,
    ];

    for (const [k, v] of Object.entries(providerConfig)) {
      lines.push(`${k} = "${v}"`);
    }

    if (githubToken) {
      lines.push("");
      lines.push("[github]");
      lines.push(`token = "${githubToken}"`);
    }

    const contents = lines.join("\n") + "\n";

    writeConfig(contents);

    err.write(chalk.green("Configuration written.\n"));
    process.exit(0);
  } catch (err: any) {
    if (err?.name === "AbortError") {
      process.stderr.write(chalk.red("\nInterrupted.\n"));
      process.exit(130);
    }

    process.stderr.write(chalk.red(`error: ${err?.message ?? err}\n`));
    process.exit(1);
  }
}

async function promptProvider(): Promise<string> {
  const err = process.stderr;

  err.write(chalk.bold("Select LLM provider:\n"));
  err.write("  1) Gemini\n");
  err.write("  2) OpenAI\n");
  err.write("  3) Ollama (local)\n");
  err.write("  4) Anthropic (Claude)\n");
  err.write("  5) Groq\n");
  err.write("  6) OpenRouter\n");

  const choice = (await prompt("> ")).trim();
  const provider = PROVIDERS[choice];

  if (!provider) {
    throw new Error("invalid provider selection");
  }

  return provider;
}

async function promptProviderConfig(
  provider: string,
): Promise<Record<string, string>> {
  if (provider === "gemini") {
    const key = (await promptHidden("Gemini API key: ")).trim();
    if (!key) throw new Error("API key cannot be empty");
    return { api_key: key };
  }

  if (provider === "openai") {
    const key = (await promptHidden("OpenAI API key: ")).trim();
    if (!key) throw new Error("API key cannot be empty");
    return { api_key: key };
  }

  if (provider === "ollama") {
    const model = (
      await prompt("Ollama model (e.g. llama3, glm-5:cloud, gemma3:4b): ")
    ).trim();

    if (!model) throw new Error("Model cannot be empty");

    const host =
      (await prompt("Ollama host [http://localhost:11434]: ")).trim() ||
      "http://localhost:11434";

    return { model, host };
  }

  if (provider === "anthropic") {
    const key = (await promptHidden("Anthropic (Claude) API key: ")).trim();
    if (!key) throw new Error("API key cannot be empty");
    return { api_key: key };
  }

  if (provider === "groq") {
    const key = (await promptHidden("Groq API key: ")).trim();
    if (!key) throw new Error("API key cannot be empty");

    const err = process.stderr;

    err.write(chalk.bold("Select Groq model:\n"));
    err.write("  1) llama3-70b-8192\n");
    err.write("  2) mixtral-8x7b\n");
    err.write("  3) deepseek-r1-distill-llama-70b\n");

    const choice = (await prompt("> ")).trim();

    const modelMap: Record<string, string> = {
      "1": "llama3-70b-8192",
      "2": "mixtral-8x7b",
      "3": "deepseek-r1-distill-llama-70b",
    };

    const model = modelMap[choice];
    if (!model) throw new Error("Invalid model selection");

    return {
      api_key: key,
      model,
    };
  }

  if (provider === "openrouter") {
    const key = (await promptHidden("OpenRouter API key: ")).trim();
    if (!key) throw new Error("API key cannot be empty");

    const err = process.stderr;

    err.write(chalk.bold("Select OpenRouter model:\n"));
    err.write("  1) openai/gpt-4o (balanced)\n");
    err.write("  2) anthropic/claude-3.5-sonnet (reasoning)\n");
    err.write("  3) meta-llama/llama-3-70b-instruct (open)\n");
    err.write("  4) deepseek/deepseek-chat (cheap/fast)\n");
    err.write("  5) Enter model manually\n");

    const choice = (await prompt("> ")).trim();

    const modelMap: Record<string, string> = {
      "1": "openai/gpt-4o",
      "2": "anthropic/claude-3.5-sonnet",
      "3": "meta-llama/llama-3-70b-instruct",
      "4": "deepseek/deepseek-chat",
    };

    let model: string;

    if (choice === "5") {
      model = (await prompt("Enter model (provider/model): ")).trim();
    } else {
      model = modelMap[choice];
      if (!model) throw new Error("Invalid model selection");
    }

    if (!model || !model.trim()) {
      throw new Error("Model cannot be empty");
    }

    return {
      api_key: key,
      model,
    };
  }

  throw new Error(`Unsupported provider: ${provider}`);
}

async function promptGithubToken(): Promise<string | null> {
  const err = process.stderr;

  err.write(
    chalk.cyan(
      "\nConfigure GitHub access for private repos and higher rate limits:\n",
    ),
  );

  const token = (await promptHidden("GitHub token (leave empty to skip): ")).trim();

  if (!token) {
    return null;
  }

  return token;
}

function prompt(label: string): Promise<string> {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stderr,
    terminal: true,
  });

  return new Promise((resolve) => {
    rl.question(label, (answer) => {
      rl.close();
      resolve(answer);
    });
  });
}

function promptHidden(label: string): Promise<string> {
  const err = process.stderr;

  return new Promise((resolve) => {
    err.write(label);

    const rl = readline.createInterface({
      input: process.stdin,
      output: undefined,
      terminal: true,
    }) as HiddenReadlineInterface;

    rl._writeToOutput = () => {};

    rl.question("", (answer) => {
      rl.close();
      err.write("\n");
      resolve(answer);
    });
  });
}

import fs from "node:fs";
import path from "node:path";

import { type RepoReadResult, type TreeItem } from "./repo_reader.js";

const KEY_FILENAMES = new Set([
  "readme.md", "readme.txt", "readme.rst", "readme",
  "package.json", "pyproject.toml", "setup.py", "setup.cfg",
  "requirements.txt", "cargo.toml", "go.mod", "pom.xml",
  "build.gradle", "composer.json", "gemfile", "makefile",
  "dockerfile", "docker-compose.yml", "docker-compose.yaml",
  ".env.example", "tsconfig.json", "angular.json", "next.config.js",
  "vite.config.js", "vite.config.ts", "webpack.config.js",
]);

const SKIP_DIRS = new Set([
  ".git", ".hg", ".svn", "node_modules", "__pycache__",
  ".venv", "venv", "env", ".env", "dist", "build",
  ".idea", ".vscode", ".mypy_cache", ".pytest_cache",
  "coverage", ".coverage", "htmlcov",
]);

const MAX_FILE_BYTES = 32_000;
const MAX_KEY_FILES = 12;

function walkDir(
  root: string,
  dir: string,
  tree: TreeItem[],
  keyFiles: Record<string, string>
): void {
  let entries: fs.Dirent[];
  try {
    entries = fs.readdirSync(dir, { withFileTypes: true });
  } catch {
    return;
  }

  const dirs: fs.Dirent[] = [];
  const files: fs.Dirent[] = [];

  for (const entry of entries) {
    if (entry.isDirectory() && !SKIP_DIRS.has(entry.name)) {
      dirs.push(entry);
    } else if (entry.isFile()) {
      files.push(entry);
    }
  }

  dirs.sort((a, b) => a.name.localeCompare(b.name));
  files.sort((a, b) => a.name.localeCompare(b.name));

  for (const file of files) {
    const absPath = path.join(dir, file.name);
    const relPath = path.relative(root, absPath).replace(/\\/g, "/");

    tree.push({ path: relPath, type: "blob" });

    if (
      KEY_FILENAMES.has(file.name.toLowerCase()) &&
      Object.keys(keyFiles).length < MAX_KEY_FILES
    ) {
      try {
        const fd = fs.openSync(absPath, "r");
        const buf = Buffer.alloc(MAX_FILE_BYTES);
        const bytesRead = fs.readSync(fd, buf, 0, MAX_FILE_BYTES, 0);
        fs.closeSync(fd);
        keyFiles[relPath] = buf.subarray(0, bytesRead).toString("utf8");
      } catch {

      }
    }
  }

  for (const subdir of dirs) {
    walkDir(root, path.join(dir, subdir.name), tree, keyFiles);
  }
}

export function readLocalRepoSignalFiles(dirPath: string): RepoReadResult {
  const root = path.resolve(dirPath);
  const tree: TreeItem[] = [];
  const keyFiles: Record<string, string> = {};

  walkDir(root, root, tree, keyFiles);

  const treeText = tree.map((item) => item.path).join("\n");

  const filesText = Object.entries(keyFiles)
    .map(([relPath, content]) => `### ${relPath}\n${content}`)
    .join("\n\n");

  return {
    tree,
    treeText,
    keyFiles,
    filesText,
    selectedFiles: Object.keys(keyFiles),
  };
}

function escapeForPromptBlock(input: string): string {
